  'shaoxing/pen': ('Колыбель каллиграфии', 'Павильон Ланьтин, связанный с именем мастера Ван Сичжи, считается священным местом для всех ценителей каллиграфии.'),
  'shaoxing/boat': ('Лодки упэн', 'Традиционные лодки с черным навесом, которыми управляют с помощью ног, являются классическим способом передвижения по каналам.'),
  'bengbu/shell': ('Жемчужный порт', 'Название города переводится как «пристань устриц», так как он был знаменит добычей жемчуга в реке Хуайхэ.'),
  'bengbu/train': ('Железнодорожный узел Бэнбу', 'Город вырос вокруг станции, расположенной на пересечении важнейшей железнодорожной магистрали север-юг через реку Хуайхэ.'),
  'bengbu/river': ('Река Хуайхэ', 'Именно здесь протекает река, которая традиционно считается географической границей между севером и югом Китая.'),
  'bengbu/blossom': ('Весенние ярмарки', 'Каждую весну городские парки на берегах реки наполняются праздничными ярмарками в период цветения.'),
  'jiujiang/mountain': ('Гора Лушань', 'Окутанные туманом вершины горы Лушань, включенной в список объектов ЮНЕСКО, веками вдохновляли китайских поэтов и художников.'),
  'jiujiang/tea': ('Чай Юньу', 'Чай «Облака и туманы», выращиваемый на склонах горы Лушань, считается одним из самых изысканных сортов в Китае.'),
  'jiujiang/lake': ('Озеро Поянху', 'Крупнейшее пресноводное озеро Китая служит местом зимовки для тысяч журавлей.'),
  'jiujiang/scroll': ('Город поэтов', 'На этих берегах реки великие поэты Бай Цзюйи и Су Ши создавали свои бессмертные строки.'),
  'quanzhou/ship': ('Морской Шелковый путь', 'Средневековый порт Цюаньчжоу, известный Марко Поло как «Зайтун», был крупнейшим торговым центром мира и объектом наследия ЮНЕСКО.'),
  'quanzhou/mosque': ('Мечеть Цинцзин', 'Эта каменная мечеть, построенная в 1009 году, является одной из старейших в Китае.'),
  'quanzhou/puppet': ('Театр марионеток', 'Искусство управления ниточными куклами в Цюаньчжоу — это древняя сценическая традиция с тысячелетней историей.'),
  'quanzhou/tea': ('Чай Тегуаньинь', 'Знаменитый во всем мире улун «Железная богиня милосердия» родом из соседнего уезда Аньси.'),
  'shanghai/pearl': ('Телебашня «Восточная жемчужина»', 'Возвышающаяся над рекой Хуанпу башня со своими розовыми сферами стала настоящим символом современного Шанхая.'),
  'shanghai/bund': ('Набережная Вайтань', 'Историческая набережная с фасадами старинных отелей отражает былое величие Шанхая.'),
  'shanghai/garden': ('Сад Юйюань', 'Классический сад эпохи Мин с его скалами и прудами представляет собой тихий оазис в самом сердце мегаполиса.'),
  'shanghai/xlb': ('Сяолунбао', 'Паровые пельмени с горячим бульоном внутри — признанный шедевр шанхайского завтрака.'),
  'hangzhou/lake': ('Сиху', 'Это озеро с ивами, островками и арочными мостиками воспето в бесчисленных китайских поэтических произведениях.'),
  'hangzhou/tea': ('Лунцзин', 'Выращенный на склонах вокруг озера, этот зеленый чай «Колодец дракона» считается самым известным в Китае.'),
  'hangzhou/temple': ('Линъинь', 'Храм «Прибежища души», основанный 1700 лет назад, славится своими наскальными рельефами и гигантской статуей Будды.'),
  'hangzhou/silk': ('Город шелка', 'Ханчжоуский шелк, который ткут уже тысячу лет, был главным богатством восточного конца Великого шелкового пути.'),
  'chongqing/hongya': ('Хунъядун', 'Этот комплекс домов на сваях, цепляющийся за скалу, по ночам сияет над рекой, словно сказочный дворец.'),
  'chongqing/hotpot': ('Чунцинский хого', 'Бурлящий острым маслом и пряными специями, этот китайский самовар является огненной душой горного города.'),
  'chongqing/monorail': ('Чунцинский монорельс', 'Поезд, проходящий прямо сквозь жилой дом, стал визитной карточкой этого города, построенного на крутых холмах.'),
  'chongqing/river': ('Ущелья Янцзы', 'Круизные лайнеры отправляются отсюда, где город возвышается над местом слияния двух великих рек.'),
  'dalian/square': ('Площадь Синхай', 'Крупнейшая городская площадь в Азии, расположенная у самого моря, часто становится местом проведения фестивалей и шоу.'),
  'dalian/beach': ('Пляжи Даляня', 'Благодаря скалистым бухтам и прохладному лету Далянь считается любимым морским курортом на севере страны.'),
  'dalian/football': ('Футбольный город', 'Далянь называют колыбелью китайского футбола, ведь именно здесь зародились самые титулованные клубы страны.'),
  'dalian/seafood': ('Морепродукты', 'Морские гребешки, креветки и морские ежи из холодных вод Желтого моря — главное украшение столов в этом городе.'),
  'shenyang/palace': ('Мукденский дворец', 'Первая резиденция династии Цин, которую часто называют младшим братом Запретного города в Пекине.'),
  'shenyang/tomb': ('Императорские гробницы династии Цин', 'Восточная и Северная гробницы, окружающие город, являются монументальными мавзолеями основателей династии.'),
  'shenyang/factory': ('Колыбель индустрии', 'Здесь зародилась тяжелая промышленность Китая, а за обилие огромных заводов город прозвали «Восточным Руром».'),
  'shenyang/dumpling': ('Пельмени «Лаобянь»', 'Паровые пельмени «Лаобянь» с двухсотлетней историей — это визитная карточка кухни северного Китая.'),
  'hefei/judge': ('Храм Бао-гуна', 'Храм посвящен легендарному судье Бао Чжэну, который родился в этих краях и стал символом справедливости и честности.'),
  'hefei/science': ('Научный центр Хэфэя', 'Технологический хаб, объединяющий ведущие университеты и научно-исследовательские лаборатории Китая.'),
  'hefei/lake': ('Озеро Чаоху', 'Одно из пяти крупнейших пресноводных озер Китая, знаменитое своими крабами и белой рыбой.'),
  'hefei/cake': ('Кунжутный пирог Лу', 'Сладкий кунжутный пирог — традиционное лакомство, история которого уходит корнями в древний Лучжоу.'),
  'foshan/wingchun': ('Вин-чунь', 'Фошань считается родиной боевого искусства вин-чунь, где начинали свой путь Ип Ман и Брюс Ли.'),
  'foshan/lion': ('Танец льва', 'Фошань — столица южного танца льва, где артисты в ярких костюмах совершают захватывающие прыжки по столбам.'),
  'foshan/ceramic': ('Керамика Шивань', 'В местных печах, работающих уже тысячу лет, до сих пор создают знаменитые живые фигурки из керамики Шивань.'),
  'foshan/opera': ('Кантонская опера', 'Именно на этих землях сформировалось и расцвело одно из самых любимых сценических искусств южного Китая.'),
  'guiyang/pavilion': ('Павильон Цзясю', 'Трехъярусный павильон на реке Наньмин уже 400 лет является главным символом города.'),
  'guiyang/sourfish': ('Рыба в кислом супе', 'Рыба, томленая в остро-кислом бульоне на основе ферментированных томатов, — главное фирменное блюдо провинции Гуйчжоу.'),
  'guiyang/waterfall': ('Водопад Хуангошу', 'Один из крупнейших водопадов Азии низвергается с грохотом, создавая в брызгах воды яркие радуги.'),
  'guiyang/miao': ('Культура народа мяо', 'Праздники и изысканная вышивка народа мяо, чьи женщины носят массивные серебряные украшения, оживляют горные деревни.'),
  'changchun/film': ('Киногород Чанчунь', 'Здесь расположены студии, где зародился китайский кинематограф, за что город прозвали «Восточным Голливудом».'),
  'changchun/car': ('Автомобильная столица', 'Чанчунь считается колыбелью китайского автопрома, ведь именно здесь с конвейера сошел первый автомобиль национального производства.'),
  'changchun/palace': ('Дворец марионеточного императора', 'Дворец, в котором жил последний император Китая, стал безмолвным свидетелем бурных исторических событий.'),
  'changchun/snow': ('Зимний снег', 'Долгими белыми зимами город сверкает ледяными скульптурами и горнолыжными трассами.'),
  'xining/lake': ('Озеро Кукунор', 'Крупнейшее соленое озеро Китая славится желтыми полями рапса, которые окружают его летом.'),
  'xining/monastery': ('Монастырь Кумбум', 'Один из шести великих монастырей тибетского буддизма, известный своими скульптурами из масла яка.'),
  'xining/flower': ('Цветение рапса', 'В июле плато до самого горизонта покрывается золотистым ковром цветущего рапса.'),
  'xining/lamb': ('Як и баранина', 'Тянутая лапша и шашлыки из баранины в традициях хуэйской и тибетской кухни — главные вкусы этого плато.'),
  'guilin/karst': ('Карстовые горы реки Ли', 'Известняковые пики, поднимающиеся из тумана, изображены на купюре в 20 юаней.'),
  'guilin/elephant': ('Гора Слоновий хобот', 'Скала в форме слона, опускающего хобот в реку, является любимым символом города.'),
  'guilin/terrace': ('Рисовые террасы Лунцзи', 'Террасы «Хребет дракона», опоясывающие склоны гор, представляют собой лестницу, созданную веками упорного труда.'),
  'guilin/osmanthus': ('Цветение османтуса', 'Название города означает «лес османтуса», и осенью он утопает в сладком аромате этих цветов.'),
  'wenzhou/merchant': ('Предпринимательский дух', 'Вэньчжоуских предпринимателей часто называют «китайскими евреями» за их умение выстраивать бизнес-сети по всему миру.'),
  'wenzhou/shoe': ('Обувь и кожа', 'Огромная доля кожаной обуви в мире производится именно в этом промышленном городе.'),
  'wenzhou/mountain': ('Горы Яньданшань', 'Эти горы, знаменитые своими водопадами и острыми пиками, называют «первыми горами у моря».'),
  'wenzhou/seafood': ('Морепродукты', 'Кальмары, гребешки и рыба из Восточно-Китайского моря составляют основу местного рациона.'),
  'tangshan/memorial': ('Мемориал землетрясения', 'Мемориальный парк, посвященный разрушительному землетрясению 1976 года, стал символом возрожденного города.'),
  'tangshan/coal': ('Угольно-сталелитейная промышленность', 'Здесь были открыты первая современная угольная шахта и железная дорога Китая, что сделало город колыбелью национальной индустрии.'),
  'tangshan/ceramic': ('Таншаньский фарфор', 'Этот город называют «северной столицей фарфора», а его изящный костяной фарфор украшает столы по всему миру.'),
  'tangshan/lake': ('Парк Наньху', 'Живописный парк с озером, разбитый на месте бывшего угольного карьера, стал «зелеными легкими» города.'),
  'anshan/steel': ('Стальной город', 'Здесь был основан крупнейший в Китае металлургический комбинат, закрепивший за Аньшанем статус «стальной столицы» страны.'),
  'anshan/jade': ('Сюяньский нефрит', 'В этом городе находится самая большая в мире нефритовая скульптура, а сам регион по праву считается краем нефрита.'),
  'anshan/mountain': ('Гора Цяньшань', 'Священная гора «Тысячи лотосов» славится своими отвесными скалами и древними буддийскими храмами.'),
  'anshan/spring': ('Горячие источники Танганцзы', 'Целебные горячие источники, которые на протяжении тысячи лет посещали даже китайские императоры.'),
  'linyi/market': ('Оптовый рынок Линьи', 'Крупнейший в Северном Китае торговый узел, откуда товары отправляются во все уголки страны.'),
  'linyi/brush': ('Родина каллиграфии', 'Здесь родился великий мастер каллиграфии Ван Сичжи, поэтому город по праву называют краем туши и кисти.'),
  'linyi/mountain': ('Гора Мэншань', 'Вторая по высоте гора провинции Шаньдун, известная своим чистейшим воздухом и живописными водопадами.'),
  'linyi/pancake': ('Блины Имын', 'Тонкие кукурузные блины «цзяньбин» являются традиционным основным блюдом жителей горных районов Имын.'),
  'cangzhou/lion': ('Железный лев', 'Огромная статуя железного льва, отлитая более тысячи лет назад, является главным символом и гордостью города.'),
  'cangzhou/martial': ('Ушу', 'Цанчжоу считается «домом ушу», где зародились многие знаменитые школы боевых искусств и выросли великие мастера.'),
  'cangzhou/canal': ('Великий канал', 'Через город проходит Великий канал Пекин — Ханчжоу, на берегах которого до сих пор сохранились старинные пристани.'),
  'cangzhou/jujube': ('Золотой финик', 'Сладкий «золотой» финик с тонкой кожицей считается королем среди сухофруктов этого региона.'),
  'nantong/textile': ('Город текстиля', 'Наньтун считается столицей домашнего текстиля, а местный хлопок поставляется на рынки по всему миру.'),
  'nantong/mountain': ('Гора Ланшань', 'Эта священная пятиглавая гора, возвышающаяся в устье Янцзы, является местом паломничества и славится своими живописными видами.'),
  'nantong/kite': ('Поющие змеи баньяо', 'Традиционные воздушные змеи баньяо, оснащенные специальными свистками, являются старинным ремеслом города.'),
  'nantong/school': ('Колыбель просвещения', 'Промышленник Чжан Цзянь основал здесь первые в Китае современные школы и музей.'),
  'taizhou/opera': ('Мэй Ланьфан', 'Тайчжоу — родина легендарного мастера пекинской оперы Мэй Ланьфана.'),
  'taizhou/tea': ('Утреннее чаепитие', 'Завтрак, состоящий из паровых булочек и свежезаваренного чая, стал для горожан настоящим утренним ритуалом.'),
  'taizhou/boat': ('Фестиваль лодок в Циньтуне', 'Весной река оживает благодаря красочному фестивалю, во время которого сотни гребцов соревнуются в скорости.'),
  'taizhou/meatball': ('Фрикадельки «Голова льва»', 'Крупные и нежные свиные фрикадельки «голова льва» являются классическим блюдом хуайянской кухни.'),
  'jinhua/ham': ('Ветчина Цзиньхуа', 'Эта ветчина, приготовленная по старинному рецепту, считается самой знаменитой в Китае.'),
  'jinhua/film': ('Киностудия Хэньдянь', 'Крупнейшая в мире открытая съемочная площадка, где снимается огромное количество исторических сериалов.'),
  'jinhua/cave': ('Пещера Шуанлун', 'В эту подземную пещеру посетители попадают на лодке через низкий каменный проход, что захватывает дух.'),
  'jinhua/bridge': ('Древние мосты', 'Арочные каменные мосты и прибрежные городки воплощают в себе изящество региона Цзяннань.'),
  'wuhu/park': ('Парк развлечений Фантэ', 'Один из крупнейших тематических парков Китая предлагает семьям незабываемый отдых и множество аттракционов.'),
  'wuhu/ironart': ('Железная живопись', 'Изящные картины, выкованные из железа, представляют собой уникальное ремесло с трехсотлетней историей.'),
  'wuhu/rice': ('Рисовый порт', 'Этот город на берегу Янцзы исторически был крупнейшим центром торговли рисом в Китае.'),
  'wuhu/river': ('Порт Уху', 'Оживленный речной порт делает этот город главными морскими воротами провинции Аньхой.'),
  'huangshan/peak': ('Хуаншань', 'Гранитные пики, море облаков и причудливые сосны делают эту гору самой знаменитой в Китае.'),
  'huangshan/village': ('Деревня Хунцунь', 'Белостенные деревни в стиле Хуэй с каналами и прудами включены в список всемирного наследия ЮНЕСКО и выглядят как ожившие картины.'),
  'huangshan/tea': ('Чай Маофэн', 'Этот зеленый чай с пушистыми почками, собранный на туманных склонах, входит в десятку самых знаменитых чаев Китая.'),
  'huangshan/ink': ('Хуэйская тушь и ремесла', 'Хуэйская тушь, резьба по дереву и каллиграфия являются культурным достоянием этого региона.'),
  'yichun/moon': ('Гора Минъюэ', 'Гора «Яркой луны» славится своими горячими источниками и живописными видами, открывающимися из кабинок канатной дороги.'),
  'yichun/spring': ('Горячие источники', 'Редкие термальные источники, богатые селеном, сделали город главным центром бальнеотерапии в Китае.'),
  'yichun/zen': ('Чань-буддизм', 'Горные храмы, ставшие колыбелью китайских сект чань-буддизма, приглашают к обретению внутреннего покоя.'),
  'yichun/rice': ('Рисовая равнина', 'Плодородная равнина Юаньхэ на протяжении долгого времени остается главной житницей провинции Цзянси.'),
  'zhangzhou/narcissus': ('Нарцисс', 'Здесь выращивают самые известные в Китае луковицы нарциссов, которые стали символом весенних праздников.'),
  'zhangzhou/tulou': ('Тулоу', 'Гигантские круглые крепости из утрамбованной земли включены в список ЮНЕСКО и позволяют целой деревне жить под одной крышей.'),
  'zhangzhou/banana': ('Тропические фрукты', 'Рощи бананов, лонгана и мандаринов сохраняют тепло дельты зеленым круглый год.'),
  'zhangzhou/coast': ('Остров Дуншань', 'Золотистые пляжи и рыбацкие деревушки делают этот остров настоящей жемчужиной южного побережья.'),
  'guangzhou/tower': ('Телебашня Гуанчжоу', 'Изящная башня, известная как «Тонкая талия», является одной из самых высоких в мире и по ночам переливается яркими огнями.'),
  'guangzhou/dimsum': ('Утренний чай', '«Ям ча» — димсамы, приготовленные на пару в бамбуковых корзинках и поданные с ароматным чаем, — это душа кантонской кухни.'),
  'guangzhou/academy': ('Академия клана Чэнь', 'Этот родовой зал, знаменитый своей резьбой по дереву и керамическими фризами, является шедевром кантонского ремесленного искусства.'),
  'guangzhou/flower': ('Город цветов', 'Благодаря круглогодичному цветению и масштабным новогодним ярмаркам Гуанчжоу по праву называют «Городом цветов».'),
  'wuhan/crane': ('Башня Желтого журавля', 'Эта тысячелетняя башня, возвышающаяся над Янцзы, вдохновила китайских поэтов на создание множества знаменитых произведений.'),
  'wuhan/noodle': ('Лапша «Ганьмянь»', 'Горячая сухая лапша с кунжутной пастой — это самый популярный и незаменимый завтрак в Ухане.'),
  'wuhan/duckneck': ('Острые утиные шеи', 'Тушеные в остром соусе утиные шеи — любимая закуска горожан для долгих вечерних посиделок.'),
  'wuhan/university': ('Сакура в Уханьском университете', 'Каждую весну полюбоваться цветением сакуры в кампусе Уханьского университета приезжают тысячи туристов.'),
  'tianjin/eye': ('Тяньцзиньское око', 'Это колесо обозрения, установленное прямо на мосту, открывает панорамный вид на оба берега реки.'),
  'tianjin/baozi': ('Баоцзы «Гоубули»', 'Паровые булочки со свининой и защипами являются визитной карточкой города с 150-летней историей.'),
  'tianjin/crosstalk': ('Сяншэн', 'Традиционный жанр парного разговорного комедийного искусства «сяншэн» зародился в чайных домах Тяньцзиня.'),
  'tianjin/architecture': ('Европейский квартал', 'Благодаря виллам в европейском стиле в районе «Пяти великих проспектов» Тяньцзинь называют музеем архитектуры под открытым небом.'),
  'xiamen/island': ('Остров Гуланъюй', 'Этот остров, включенный в список объектов ЮНЕСКО, представляет собой музей под открытым небом с колониальными виллами и пешеходными улочками.'),
  'xiamen/piano': ('Остров пианино', 'Гуланъюй называют «островом пианино», так как здесь на душу населения приходится больше фортепиано, чем в любом другом месте Китая.'),
  'xiamen/egret': ('Белая цапля', 'Белая цапля является символом города и напоминает о его старом названии — «Остров цапель».'),
  'xiamen/oyster': ('Омлет с устрицами', 'Хрустящий омлет со свежими устрицами — главное блюдо местной прибрежной кухни.'),
  'harbin/ice': ('Фестиваль льда и снега', 'Зимний фестиваль в Харбине, где возводят гигантские подсвеченные ледяные дворцы, является крупнейшим в мире.'),
  'harbin/cathedral': ('Софийский собор', 'Этот православный собор с куполами-луковицами является символом европейского прошлого города.'),
  'harbin/sausage': ('Красная колбаса', 'Копченая красная колбаса в русском стиле — это местный деликатес с вековой историей.'),
  'harbin/accordion': ('Музыкальный город', 'Благодаря богатому русскому наследию именно в Харбине был основан первый в Китае симфонический оркестр.'),
  'fuzhou/alley': ('Три переулка и семь аллей', 'Этот старинный квартал с белыми стенами и черной черепицей представляет собой живой музей архитектуры эпох Мин и Цин.'),
  'fuzhou/banyan': ('Город баньянов', 'Фучжоу называют «городом баньянов», так как древние гигантские деревья создают густую тень на его улицах.'),
  'fuzhou/hotspring': ('Горячие источники', 'Бьющие прямо в центре города горячие источники уже тысячу лет питают местные общественные бани.'),
  'fuzhou/soup': ('Будда прыгает через стену', 'Этот изысканный суп, приготовленный из десятков ингредиентов, считается шедевром фуцзяньской кухни.'),
  'dongguan/robot': ('Мировая фабрика', 'Благодаря автоматизированным производствам Дунгуань выпускает огромную долю всей мировой электроники.'),
  'dongguan/basketball': ('Баскетбольный город', 'В этом городе, известном как «баскетбольная столица», базируется самый титулованный баскетбольный клуб Китая.'),
  'dongguan/keyuan': ('Сад Кэюань', 'Один из четырех знаменитых классических садов провинции Гуандун, который славится своими прудами и павильонами.'),
  'dongguan/cannon': ('Крепости Хумынь', 'Крепости Хумынь, где началась Опиумная война, стоят на берегу, где когда-то уничтожали партии опиума.'),
  'lanzhou/beefnoodle': ('Ланьчжоуская лапша с говядиной', 'Ланьчжоу по праву считается столицей лапши благодаря прозрачному говяжьему бульону и мастерству ручного вытягивания теста.'),
  'lanzhou/waterwheel': ('Водяные колеса', 'Гигантские водяные колеса на реке Хуанхэ символизируют многовековую историю ирригационной инженерии.'),
  'lanzhou/statue': ('Мать Хуанхэ', 'Скульптура матери с ребенком на берегу реки олицетворяет великую реку, ставшую колыбелью китайской цивилизации.'),
  'lanzhou/raft': ('Плоты из овечьих шкур', 'Традиционные плоты из надутых овечьих шкур до сих пор можно увидеть на реке Хуанхэ.'),
  'urumqi/bazaar': ('Международный большой базар', 'С его минаретами и прилавками с пряностями этот базар сохраняет атмосферу Великого шелкового пути.'),
  'urumqi/tianshan': ('Тяньчи', 'Озеро Тяньчи, расположенное у подножия заснеженных пиков Тянь-Шаня, окружено густыми еловыми лесами.'),
  'urumqi/kebab': ('Шашлык из баранины', 'Ароматный шашлык из баранины, приготовленный на углях, является обязательным блюдом уйгурской кухни.'),
  'urumqi/dance': ('Уйгурский танец', 'Зажигательные уйгурские танцы под аккомпанемент барабанов и равапа украшают любой праздник.'),
  'haikou/coconut': ('Город кокосов', 'Улицы, обсаженные кокосовыми пальмами, подарили Хайкоу прозвище «город кокосов».'),
  'haikou/arcade': ('Аркады Цилоу', 'Южные здания с колоннадами в стиле «цилоу» образуют тенистые торговые улицы.'),
  'haikou/crater': ('Вулканические кратеры', 'Потухшие вулканические кратеры образуют живописный зеленый геопарк на окраине города.'),
  'haikou/turtle': ('Тропическое море', 'Теплые прозрачные воды и коралловые рифы делают побережье идеальным домом для морских черепах.'),
  'luoyang/grotto': ('Гроты Лунмэнь', 'Десятки тысяч статуй Будды, высеченных в скалах, представляют собой сокровищницу искусства, включенную в список ЮНЕСКО.'),
  'luoyang/peony': ('Столица пионов', 'Тысячи пионов, расцветающих каждый апрель, делают Лоян настоящей «столицей пионов».'),
  'luoyang/whitehorse': ('Храм Белой лошади', 'Основанный в 68 году нашей эры, этот храм считается первым буддийским монастырем в Китае.'),
  'luoyang/capital': ('Древняя столица', 'Будучи столицей тринадцати династий, Лоян считается одной из колыбелей китайской цивилизации.'),
  'shantou/gongfutea': ('Чайная церемония Гунфу', 'Чаошаньская чайная церемония гунфу, где чай заваривают в крошечных чашках, — это настоящее искусство гостеприимства.'),
  'shantou/beefpot': ('Говяжий хого', 'Чаошаньский хого, в котором тонкие ломтики свежей говядины готовятся за считанные секунды, славится своим вкусом.'),
  'shantou/opera': ('Чаочжоуская опера', 'Чаочжоуская опера с 600-летней историей известна своими утонченными песнями и роскошными вышитыми костюмами.'),
  'shantou/harbor': ('Порт Шаньтоу', 'Этот город, ставший родиной для многих китайских эмигрантов, на протяжении веков служил важными морскими воротами для международной торговли.'),
  'baoding/mansion': ('Резиденция губернатора', 'Это прекрасно сохранившееся здание эпохи династии Цин когда-то было главной административной резиденцией провинции.'),
  'baoding/donkeyburger': ('Бургер с ослиным мясом', 'Визитная карточка местной уличной кухни — хрустящая лепешка, начиненная пряным мясом осла.'),
  'baoding/balls': ('Шары здоровья', 'Традиция вращения металлических шаров в ладони для тренировки рук насчитывает уже несколько столетий.'),
  'baoding/reeds': ('Болота Байяндянь', 'Крупнейшая водно-болотная зона на севере страны представляет собой настоящий рай для птиц среди зарослей тростника и лотосов.'),
  'jilin/rime': ('Иней на деревьях', 'Белоснежный иней, покрывающий деревья вдоль берегов реки Сунгари, считается одним из четырех главных природных чудес Китая.'),
  'jilin/snowboard': ('Горнолыжный курорт', 'Благодаря глубокому снегу и продолжительному сезону город стал одним из лучших мест для катания на лыжах на севере страны.'),
  'jilin/meteorite': ('Музей метеоритов', 'Здесь выставлен крупнейший в мире каменный метеорит, упавший на Землю в 1976 году.'),
  'jilin/skate': ('Замерзшая Сунгари', 'Зимой замерзшая река Сунгари превращается в огромный каток, где любят кататься на коньках и гулять местные жители.'),
  'ordos/khan': ('Мавзолей Чингисхана', 'Величественный мавзолей, посвященный герою степей Чингисхану, является духовным центром монгольской культуры.'),
  'ordos/cashmere': ('Кашемир', 'Изделия из шерсти ордосских коз прославили город на весь мир в текстильной индустрии.'),
  'ordos/sanddune': ('Поющие пески', 'Огромные дюны пустыни Кубуци, издающие гудящий звук при спуске с них, стали излюбленным местом туристов.'),
  'ordos/yurt': ('Монгольская юрта', 'Белые войлочные юрты, установленные посреди бескрайней степи, являются главным символом кочевого образа жизни.'),
  'jining/confucius': ('Храм Конфуция', 'Расположенные в соседнем Цюйфу храм, усадьба и могила великого мудреца Конфуция включены в список всемирного наследия ЮНЕСКО.'),
  'jining/barge': ('Великий канал', 'Будучи оживленным портом на Великом канале, Цзинин исторически являлся важным центром культуры судоходства.'),
  'jining/sword': ('Герои Ляншаня', 'Сто восемь легендарных разбойников из классического романа «Речные заводи» собирались в этих болотистых холмах.'),
  'jining/fishnet': ('Озеро Вэйшань', 'На крупнейшем на севере лотосовом озере рыбаки до сих пор используют старинные методы ловли.'),
  'langfang/culture': ('Культурный центр Шелкового пути', 'В этом огромном современном центре собраны произведения искусства, связанные с историей Шелкового пути.'),
  'langfang/furniture': ('Город мебели', 'Соседний уезд Сянхэ является одним из крупнейших в Китае центров производства и торговли мебелью.'),
  'langfang/tunnel': ('Древние военные туннели', 'Тысячелетние подземные военные ходы когда-то служили важным оборонительным рубежом.'),
  'langfang/themepark': ('Парк «Город номер один»', 'Огромный тематический парк, воссоздающий облик древнего города-крепости, открыт для семейного отдыха.'),
  'yancheng/salt': ('Город соли', 'Название города переводится как «соляная крепость», ведь на протяжении веков он был центром соледобычи в Китае.'),
  'yancheng/crane': ('Японский журавль', 'Прибрежные водно-болотные угодья являются крупнейшим в мире местом зимовки диких японских журавлей.'),
  'yancheng/elk': ('Олень Давида', 'Когда-то полностью исчезнувший в дикой природе, олень Давида был успешно возрожден в этих заповедных местах.'),
  'yancheng/wetland': ('Прибрежные водно-болотные угодья', 'Внесенные в список ЮНЕСКО приливные отмели служат важной остановкой для перелетных птиц со всего мира.'),
  'huzhou/brush': ('Кисть Ху', 'Знаменитая кисть Ху, одна из «четырех драгоценностей» китайской каллиграфии, производится именно здесь.'),
  'huzhou/bamboo': ('Бамбуковое море Аньцзи', 'Бескрайние зеленые бамбуковые леса, ставшие источником вдохновения для многих фильмов, сохраняют здесь прохладу.'),
  'huzhou/silkworm': ('Шелкопряд', 'Южный берег озера Тайху на протяжении тысячи лет остается центром производства шелка из тутового шелкопряда.'),
  'huzhou/whitetea': ('Белый чай из Аньцзи', 'Благодаря своим светлым листьям и сладкому вкусу белый чай из Аньцзи считается одним из самых редких сортов в Китае.'),
  'quzhou/go': ('Го', 'Благодаря легенде о горе Ланькэ город почитается как священное место для любителей игры в го.'),
  'quzhou/peaks': ('Гора Цзянлан', 'Три гигантских каменных столба, устремленных в небо, образуют уникальный ландшафт, включенный в список объектов всемирного наследия ЮНЕСКО.'),
  'quzhou/ponkan': ('Мандарины понкань из Цюйчжоу', 'Сладкие мандарины понкань с тонкой кожицей — это зимний дар мягкого климата местных холмов.'),
  'quzhou/cake': ('Лепешки с кунжутом', 'Хрустящие кунжутные лепешки, выпеченные на стенках печи, являются классическим местным завтраком.'),
  'huainan/tofu': ('Родина тофу', 'Изобретенный на горе Багун две тысячи лет назад, тофу именно отсюда начал свое распространение по всему миру.'),
  'huainan/coalmine': ('Угольная столица', 'Богатый залежами угля, Хуайнань является важнейшей энергетической базой восточного Китая.'),
  'huainan/oldtown': ('Старый город Шоусянь', 'Полностью сохранившаяся городская стена эпохи Сун представляет собой редкий образец древнего оборонительного зодчества.'),
  'huainan/classic': ('Хуайнань-цзы', 'Классический философский трактат, составленный принцем Лю Анем, был написан именно на этих землях.'),
  'jingdezhen/porcelain': ('Фарфоровая столица', 'Производя императорский фарфор на протяжении тысячи лет, город по праву считается мировой столицей этого ремесла.'),
  'jingdezhen/kiln': ('Древние печи', 'Дровяные печи в форме дракона до сих пор поддерживают жизнь традиционного искусства обжига фарфора.'),
  'jingdezhen/bluewhite': ('Сине-белый фарфор', 'Белый фарфор с кобальтовой росписью является всемирно известной визитной карточкой города.'),
  'jingdezhen/painting': ('Фарфоровая живопись', 'Фарфор, расписанный мастерами с помощью тончайших кистей, ценится наравне с произведениями классической живописи.'),
  'jian/jinggang': ('Горы Цзинганшань', 'Туманные горы, ставшие первой базой революции, являются сердцем «красного туризма».'),
  'jian/torch': ('Революционная искра', 'Земля, где родилась фраза «одна искра может разжечь пламя», является важным историческим мемориалом.'),
  'jian/academy': ('Академия Байлучжоу', 'Тысячелетняя академия, расположенная на острове посреди реки Гань, воспитала бесчисленное множество имперских ученых.'),
  'jian/pine': ('Сосны Цзинганшань', 'Красные сосны, пробивающиеся сквозь туман, символизируют горный дух и стойкость.'),
  'nanping/wuyi': ('Уишань', 'Эти горы, включенные в список всемирного наследия ЮНЕСКО, славятся своими красными скалами и живописными зелеными ущельями.'),
  'nanping/rocktea': ('Утесный чай', 'Выращенный на скалах улун «Да Хун Пао» считается одним из самых дорогих сортов чая в мире.'),
